// access expressions like ${note.title}; rejects arbitrary JS expressions.
function interpolateTemplate(template: string, context: Record<string, unknown>): string {
    return template.replace(/\$\{([^}]+)\}/g, (match, expr: string) => {
        const parts = expr.trim().split(".");
        // Reject expressions containing anything other than identifiers and dots
        if (!/^[a-zA-Z_$][a-zA-Z0-9_$.]*$/.test(expr.trim())) {
            return match;
        }
        let value: unknown = context;
        for (const part of parts) {
            if (value == null || typeof value !== "object") return match;
            value = (value as Record<string, unknown>)[part];
        }
        return value != null ? String(value) : "";
    });
}

